import React, { useState } from "react";

export default function SettingsPanel() {
  const [theme, setTheme] = useState("light");
  const [mentions, setMentions] = useState(true);
  const [invites, setInvites] = useState(true);
  const [waveAlerts, setWaveAlerts] = useState(false);
  const [sounds, setSounds] = useState(true);
  const [haptics, setHaptics] = useState(true);
  const [analytics, setAnalytics] = useState(false);
  const [visibility, setVisibility] = useState("friends");

  const Section = ({ title, children }) => (
    <div className="settings-section">
      <p className="settings-section-title">{title}</p>
      <div className="settings-card">{children}</div>
    </div>
  );

  const Item = ({ icon, label, hint, trailing, onClick }) => (
    <button type="button" className="settings-item" onClick={onClick}>
      <span className="settings-left">
        <span className="settings-icon">{icon}</span>
        <span className="settings-text">
          <strong>{label}</strong>
          {hint ? <small>{hint}</small> : null}
        </span>
      </span>
      <span className="settings-trailing">{trailing || "›"}</span>
    </button>
  );

  const Toggle = ({ checked, onChange }) => (
    <label className="settings-toggle">
      <input type="checkbox" checked={checked} onChange={(event) => onChange(event.target.checked)} />
      <span className="settings-toggle-track">
        <span className="settings-toggle-thumb" />
      </span>
    </label>
  );

  return (
    <section className="settings-panel glass">
      <header className="settings-head">
        <p className="eyebrow">Settings</p>
        <h2>Make Wavvy yours</h2>
        <p className="muted">Account, preferences, privacy, and help.</p>
      </header>

      <div className="settings-grid">
        <Section title="Account & Profile">
          <Item icon="👤" label="Profile" hint="Name, photo, bio" />
          <Item icon="@" label="Username / Handle" />
          <Item icon="😎" label="Status / Mood" hint="Share your wave vibe" />
        </Section>

        <Section title="App Preferences">
          <Item icon="🔔" label="Mentions" trailing={<Toggle checked={mentions} onChange={setMentions} />} />
          <Item icon="✉️" label="Room invites" trailing={<Toggle checked={invites} onChange={setInvites} />} />
          <Item icon="🌊" label="Wave alerts" trailing={<Toggle checked={waveAlerts} onChange={setWaveAlerts} />} />
          <Item icon="🔊" label="Sounds" trailing={<Toggle checked={sounds} onChange={setSounds} />} />
          <Item icon="📳" label="Haptics" trailing={<Toggle checked={haptics} onChange={setHaptics} />} />
        </Section>

        <Section title="Privacy & Safety">
          <Item icon="🚫" label="Blocked users" />
          <Item
            icon="👀"
            label="Who can see me"
            hint={visibility === "friends" ? "Friends only" : visibility}
            trailing={visibility}
            onClick={() => setVisibility(visibility === "public" ? "friends" : "public")}
          />
          <Item icon="📈" label="Data sharing" trailing={<Toggle checked={analytics} onChange={setAnalytics} />} />
          <Item icon="⚠️" label="Report a problem" />
        </Section>

        <Section title="Social & Community">
          <Item icon="📁" label="My rooms" />
          <Item icon="🧭" label="Discover preferences" hint="Waves, people, topics" />
        </Section>

        <Section title="Help & Info">
          <Item icon="❓" label="Help Center" />
          <Item icon="ℹ️" label="About Wavvy" />
          <Item icon="📜" label="Terms & Privacy" />
          <Item icon="🚪" label="Log out" trailing="›" />
        </Section>
      </div>
    </section>
  );
}
